// Fetch the linked roster from Supabase. Each linked agent has an
// adp_associate_oid we can hand to the Apify actor; the actor uses
// it to make sure the per-worker /hr/v2/workers/{oid} detail call
// happens for every linked person (otherwise terminated agents who
// fall off the active list never get hydrated).
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://YOUR_SUPABASE_PROJECT.supabase.co/rest/v1';
const hdr = { apikey };

const rows = await this.helpers.httpRequest({
  method: 'GET',
  url: base + '/agents?select=id,name,is_active,adp_associate_oid,adp_status,adp_status_effective_date,adp_job_title,adp_work_email,terminated_date,hired_date',
  headers: hdr,
  json: true,
});

if (!Array.isArray(rows) || rows.length === 0) {
  return [{ json: { error: true, message: 'No agents in Supabase' } }];
}

const linked = rows.filter((r) => r.adp_associate_oid);
const linkedOids = linked.map((r) => r.adp_associate_oid);

// Snapshot the current state so the post-actor diff node can compare
// without re-querying Supabase.
const preState = {};
for (const r of rows) {
  if (r.adp_associate_oid) {
    preState[r.adp_associate_oid] = {
      id: r.id,
      name: r.name,
      is_active: r.is_active,
      adp_status: r.adp_status,
      adp_status_effective_date: r.adp_status_effective_date,
      adp_job_title: r.adp_job_title,
      adp_work_email: r.adp_work_email,
      terminated_date: r.terminated_date,
    };
  }
}

return [{
  json: {
    totalAgents: rows.length,
    linkedCount: linked.length,
    unlinkedCount: rows.length - linked.length,
    linkedOids,
    preState,
    apifyBody: JSON.stringify({
      adpClientId: 'YOUR_ADP_CLIENT_ID',
      adpClientSecret: 'YOUR_ADP_CLIENT_SECRET',
      // PEMs MUST use template-literal backticks once injected — the multi-line cert breaks JSON if quoted with single/double quotes. The build script swaps these placeholders for `-----BEGIN ... -----` style backtick blobs.
      adpCertPem: 'YOUR_ADP_CERT_PEM',
      adpKeyPem: 'YOUR_ADP_KEY_PEM',
      linkedOids,
      // Only emit XAJ (Digital Senior Benefits) workers; linked agents bypass the filter.
      companyCodeAllowlist: ['XAJ'],
      salesTitleKeywords: ['agent', 'sales', 'producer'],
      pageSize: 100,
      requestDelayMs: 250,
    }),
  },
}];

// Pull dataset items, diff vs preState, PATCH agents rows, and
// build the change list for Slack. One n8n item out: the Slack payload.
const runStatus = $input.first().json;
const datasetId = runStatus?.data?.defaultDatasetId;
const runId = runStatus?.data?.id || 'unknown';
if (!datasetId) {
  return [{ json: { error: true, message: 'No defaultDatasetId. runId=' + runId } }];
}

const apifyToken = 'YOUR_APIFY_TOKEN';
const supaApikey = 'YOUR_SUPABASE_ANON_KEY';
const supaBase = 'https://YOUR_SUPABASE_PROJECT.supabase.co/rest/v1';
const supaHdr = {
  apikey: supaApikey,
  Authorization: 'Bearer ' + supaApikey,
  'Content-Type': 'application/json',
  Prefer: 'return=minimal',
};

// preState was computed in the Fetch node and we need it back here. n8n only
// passes the latest item through, so we re-fetch instead of trying to thread
// state through a 6-node chain. Same query, single round-trip.
const rows = await this.helpers.httpRequest({
  method: 'GET',
  url: supaBase + '/agents?select=id,name,is_active,adp_associate_oid,adp_status,adp_status_effective_date,adp_job_title,adp_work_email,terminated_date,hired_date',
  headers: { apikey: supaApikey },
  json: true,
});
const preState = {};
for (const r of (rows || [])) {
  if (r.adp_associate_oid) preState[r.adp_associate_oid] = r;
}

const datasetUrl = `https://api.apify.com/v2/datasets/${datasetId}/items?token=${apifyToken}`;
let items;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    const raw = await this.helpers.httpRequest({
      method: 'GET', url: datasetUrl, encoding: 'utf-8',
      timeout: 60000, headers: { Accept: 'application/json' },
    });
    items = typeof raw === 'string' ? JSON.parse(raw) : raw;
    if (Array.isArray(items)) break;
  } catch (err) { if (attempt === 3) throw err; await new Promise((r) => setTimeout(r, 5000)); }
}
if (!Array.isArray(items)) {
  return [{ json: { error: true, message: 'Dataset fetch returned non-array', datasetId } }];
}

const workers = items.filter((i) => i._type === 'adp_worker');
const summary = items.find((i) => i._type === 'adp_roster_sync_summary') || {};

const todayUtc = new Date().toISOString();
const statusChanges = [];
const newSalesHires = [];
const patchErrors = [];
let patched = 0;

for (const w of workers) {
  const oid = w.associate_oid;
  const prev = preState[oid];

  if (!prev) {
    // Worker not yet linked to any ROLI agent. Only Slack-worthy if sales role.
    if (w.is_sales_role) {
      newSalesHires.push({
        oid,
        name: w.legal_full_name,
        title: w.job_title || w.job_code,
        hire_date: w.hire_date || w.original_hire_date,
        status: w.status_code,
        email: w.work_email,
      });
    }
    continue;
  }

  // Detect material changes for Slack callouts
  const before = prev.adp_status;
  const after = w.status_code;
  const goingTerminated = before !== 'T' && after === 'T';
  const goingActive = before === 'T' && after === 'A';
  const titleChanged = (prev.adp_job_title || '') !== (w.job_title || '');
  const adpHireDate = w.original_hire_date || w.hire_date || null;
  const hireDateChanged = adpHireDate && (prev.hired_date || '') !== adpHireDate;

  if (goingTerminated || goingActive || titleChanged || hireDateChanged) {
    let kind = 'TITLE_CHANGE';
    if (goingTerminated) kind = 'TERMINATED';
    else if (goingActive) kind = 'REACTIVATED';
    else if (hireDateChanged && !titleChanged) kind = 'HIRE_DATE_CHANGE';
    statusChanges.push({
      oid,
      roli_name: prev.name,
      adp_name: w.legal_full_name,
      from_status: before || '(none)',
      to_status: after || '(none)',
      effective_date: w.status_effective_date || '',
      title_change: titleChanged ? `${prev.adp_job_title || '(blank)'} -> ${w.job_title || '(blank)'}` : null,
      hire_date_change: hireDateChanged ? `${prev.hired_date || '(blank)'} -> ${adpHireDate}` : null,
      kind,
    });
  }

  // PATCH the agents row.
  // - Always refresh adp_status, adp_status_effective_date, adp_job_title,
  //   adp_work_email, adp_synced_at.
  // - If TERMINATED in ADP, set is_active=false + terminated_date (only if
  //   not already set so we don't overwrite a hand-entered date).
  // - If REACTIVATED in ADP and our row is still inactive, leave is_active
  //   alone — re-activating an agent has historical-data implications and
  //   should be a human decision; the Slack alert prompts the action.
  const patchBody = {
    adp_status: w.status_code,
    adp_status_effective_date: w.status_effective_date || null,
    adp_job_title: w.job_title || null,
    adp_work_email: w.work_email || null,
    adp_synced_at: todayUtc,
  };
  // hired_date — prefer originalHireDate (survives rehires) over assignment hireDate
  if (adpHireDate) patchBody.hired_date = adpHireDate;
  if (goingTerminated) {
    patchBody.is_active = false;
    if (!prev.terminated_date) {
      patchBody.terminated_date = w.status_effective_date || null;
    }
  }

  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${supaBase}/agents?adp_associate_oid=eq.${encodeURIComponent(oid)}`,
      headers: supaHdr,
      body: JSON.stringify(patchBody),
    });
    patched += 1;
  } catch (err) {
    patchErrors.push({ oid, name: prev.name, message: err.message || String(err) });
  }
}

// Build Slack message
const lines = [];
lines.push(`:adhesive_bandage: *ADP Roster Sync* — ${summary.total_workers_in_adp || '?'} workers in ADP, ${patched} ROLI agents refreshed`);

if (statusChanges.length === 0 && newSalesHires.length === 0 && patchErrors.length === 0) {
  lines.push(`· no changes — all linked agents healthy`);
} else {
  if (statusChanges.length > 0) {
    lines.push(`*${statusChanges.length} status change(s):*`);
    for (const c of statusChanges) {
      let tag = ':pencil2: TITLE';
      if (c.kind === 'TERMINATED') tag = ':warning: TERMINATED';
      else if (c.kind === 'REACTIVATED') tag = ':rotating_light: REACTIVATED';
      else if (c.kind === 'HIRE_DATE_CHANGE') tag = ':calendar: HIRE_DATE';
      const detailParts = [];
      if (c.title_change) detailParts.push(c.title_change);
      if (c.hire_date_change) detailParts.push('hire ' + c.hire_date_change);
      const detail = detailParts.length > 0 ? ' | ' + detailParts.join(' | ') : '';
      lines.push(`  ${tag} — ${c.roli_name} (${c.adp_name}) | ${c.from_status} → ${c.to_status}${c.effective_date ? ' eff ' + c.effective_date : ''}${detail}`);
    }
  }
  if (newSalesHires.length > 0) {
    lines.push(`*${newSalesHires.length} unlinked sales worker(s) in ADP — onboard or alias:*`);
    for (const n of newSalesHires) {
      lines.push(`  :new: ${n.name} | ${n.title || '(no title)'} | hired ${n.hire_date || '?'} | OID=${n.oid}`);
    }
  }
  if (patchErrors.length > 0) {
    lines.push(`*:rotating_light: ${patchErrors.length} PATCH failure(s):*`);
    for (const e of patchErrors) lines.push(`  ${e.name}: ${e.message}`);
  }
}

return [{
  json: {
    text: lines.join('\n'),
    runId,
    summary,
    statusChanges,
    newSalesHires,
    patchErrors,
    patched,
  },
}];
